
import Image from "next/image";
import { lostItems } from "@/app/data/lostitem";
import { foundItems } from "@/app/data/founditem";


const ItemDetails = ({params}) => {
   
    const {id}= params;
    //console.log("hello");
     //console.log(params);
    //console.log(id);
    const item= lostItems.find((it)=>it.id==id) || foundItems.find((it)=>it.id==id);

    if (!item) return <div className="p-10 text-center">Item not found.</div>;

   return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-3xl font-bold mb-4">{item.title}</h1>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <Image
          src={item.image}
          width={500}
          height={500}
          alt={item.title}
          className="rounded-xl shadow"
        />

        <div>
          <p className="text-gray-700 mb-3">{item.description}</p>
          <p className="text-gray-500 mb-3">
            <b>Status:</b> {item.status}
          </p>

          <a
            href={`/claim/${item.id}`}
            className="bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-500"
          >
            Claim This Item
          </a>
        </div>
      </div>
    </div>
  );
}


export default ItemDetails